// Wraps any <img> with a .png/.jpg/.jpeg src in a <picture> that prefers a .webp sibling.
// Assumes the .webp exists on disk at the sibling URL (generated by scripts/generate-webp.mjs).
// Only touches images at absolute paths — external URLs and data URIs are left alone.
import { visit } from "unist-util-visit";

export default function rehypePictureWebp() {
  return (tree) => {
    visit(tree, "element", (node, index, parent) => {
      if (!parent || typeof index !== "number") return;
      if (node.tagName !== "img") return;

      const src = node.properties?.src;
      if (typeof src !== "string") return;
      if (!src.startsWith("/") || src.startsWith("//")) return;

      const m = src.match(/^(.+)\.(png|jpg|jpeg)$/i);
      if (!m) return;
      const webpSrc = `${m[1]}.webp`;

      parent.children[index] = {
        type: "element",
        tagName: "picture",
        properties: {},
        children: [
          {
            type: "element",
            tagName: "source",
            properties: { type: "image/webp", srcSet: webpSrc },
            children: [],
          },
          node,
        ],
      };
    });
  };
}
